import { IMessageComposer } from '@nitrots/nitro-renderer';

export class DoorDashOrderComposer implements IMessageComposer<any[]> {
    private _data: any[];

    /**
     * orderType:
     * 1 = Pizza Delivery (you can add more types later if you like)
     */
    constructor(orderType: number = 1) {
        const type = Math.max(1, Math.floor(orderType || 1));
        this._data = [type];
        console.log('[📤] DoorDashOrderComposer packet sent:', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
